t.script:
function toggleConfig(btn, id) {
    var panel = document.getElementById(id);
    if (!panel) return;
    var open = panel.classList.toggle('open');
    btn.textContent = open ? '▲ Hide Config' : '📄 View Config';
}
function switchTab(prefix, name) {
    var container = document.getElementById(prefix);
    if (!container) return;
    container.querySelectorAll('.config-tab').forEach(function(t) { t.classList.remove('active'); });
    container.querySelectorAll('.config-panel').forEach(function(p) { p.classList.remove('active'); });
    event.target.classList.add('active');
    var panel = document.getElementById(prefix + '-' + name);
    if (panel) panel.classList.add('active');
}
function copyCode(id, btn) {
    var text = document.getElementById(id).textContent;
    navigator.clipboard.writeText(text).then(function() {
        btn.textContent = '✓ Copied!';
        btn.classList.add('copied');
        setTimeout(function() { btn.textContent = '📋 Copy'; btn.classList.remove('copied'); }, 2500);
    }).catch(function() {
        var ta = document.createElement('textarea');
        ta.value = text; document.body.appendChild(ta); ta.select();
        document.execCommand('copy'); document.body.removeChild(ta);
        btn.textContent = '✓ Copied!';
        setTimeout(function() { btn.textContent = '📋 Copy'; }, 2500);
    });
}

