// Build download file from all configs on the page
document.getElementById('dl-btn').addEventListener('click', function() {
    var key      = document.getElementById('key-code').textContent.trim();
    var claude   = document.getElementById('claude-code').textContent.trim();
    var cursor   = document.getElementById('cursor-config').textContent.trim();
    var cont     = document.getElementById('continue-config').textContent.trim();
    var desk     = document.getElementById('desktop-config').textContent.trim();
    var gemini   = document.getElementById('gemini-config').textContent.trim();
    var codex    = document.getElementById('codex-config').textContent.trim();
    var opencode = document.getElementById('opencode-config').textContent.trim();
    var chatgpt  = document.getElementById('chatgpt-url').textContent.trim();
    var oai      = document.getElementById('openai-config').textContent.trim();
    var txt = [
        '# Odoo MCP Server — Connection Config',
        '# Generated: ' + new Date().toISOString(),
        '# KEEP THIS FILE SECURE — treat like a password',
        '',
        '== YOUR API KEY ==',
        key,
        '',
        '== Claude Code (run in terminal) ==',
        claude,
        '',
        '== Cursor IDE (.cursor/mcp.json) ==',
        cursor,
        '',
        '== Continue.dev (~/.continue/config.json) ==',
        cont,
        '',
        '== Claude Desktop (claude_desktop_config.json) ==',
        desk,
        '',
        '== Gemini CLI (~/.gemini/settings.json) ==',
        gemini,
        '',
        '== Codex CLI (~/.codex/config.yaml) ==',
        codex,
        '',
        '== OpenCode (opencode.json) ==',
        opencode,
        '',
        '== ChatGPT Native MCP (paste as Server URL) ==',
        chatgpt,
        '',
        '== OpenAI Python bridge ==',
        oai,
    ].join('\n');
    var blob = new Blob([txt], {type: 'text/plain'});
    var a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = 'odoo-mcp-config.txt';
    a.click();
});
